(async function pushToGitHub() {
  const TOKEN = "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";
  const URL   = "https://api.github.com/repos/VinupaHelitha/investsmart/contents/app.py";
  const NEW_B64 = ``;

  console.log("Fetching current SHA...");
  const getResp = await fetch(URL, { headers: { "Authorization": "token " + TOKEN } });
  const getData = await getResp.json();
  const sha = getData.sha;
  console.log("SHA:", sha);

  console.log("Pushing security hardened build...");
  const putResp = await fetch(URL, {
    method: "PUT",
    headers: { "Authorization": "token " + TOKEN, "Content-Type": "application/json" },
    body: JSON.stringify({
      message: "Security hardening: XSS prevention, input validation, Google OAuth error handling",
      content: NEW_B64,
      sha: sha
    })
  });
  const putData = await putResp.json();
  if (putData.commit) {
    console.log("SUCCESS! Commit:", putData.commit.sha);
    return "SUCCESS: " + putData.commit.sha;
  } else {
    console.error("FAILED:", JSON.stringify(putData));
    return "FAILED";
  }
})()